'use strict';

const fs = require('fs');
const { allProducts } = require('../core/products.js');
const { AppError } = require('../lib/errors.js');
const config = require('../config.js');

function exportProducts(args) {
  const formatIndex = args.indexOf('--format');
  if (formatIndex === -1 || formatIndex + 1 >= args.length) {
    throw new AppError('usage: export-products --format <json|csv>', 2);
  }

  const format = args[formatIndex + 1];
  if (format !== 'json' && format !== 'csv') {
    throw new AppError(`unsupported format: ${format}`, 2);
  }

  fs.mkdirSync(config.outputDir, { recursive: true });

  const records = allProducts();
  const filePath = `${config.outputDir}/products.${format}`;

  if (format === 'csv') {
    const lines = ['id,name,price', ...records.map(r => `${r.id},${r.name},${r.price}`)];
    fs.writeFileSync(filePath, lines.join('\n'));
  } else {
    fs.writeFileSync(filePath, JSON.stringify(records, null, 2));
  }

  return [`exported products to out/products.${format}`];
}

module.exports = { exportProducts };

